__enhancd::cd () {
	local -i code=0 
	local -a args opts
	if ! __enhancd::cd::ready
	then
		__enhancd::cd::builtin "${@:-$HOME}"
		return ${?}
	fi
	if [[ -p /dev/stdin ]]
	then
		args+=("$(command cat <&0 | __enhancd::filter::interactive)") 
	fi
	while (( ${#} > 0 ))
	do
		case "${1}" in
			(-h | --help) __enhancd::ltsv::open | __enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/help.awk"
				return ${?} ;;
			("${ENHANCD_ARG_HYPHEN}") args+=("$(__enhancd::sources::mru | __enhancd::filter::interactive)") 
				code=${?} 
				break ;;
			("-") args+=("${OLDPWD}") 
				break ;;
			("${ENHANCD_ARG_DOUBLE_DOT}") args+=("$(__enhancd::sources::parent_dirs | __enhancd::filter::interactive)") 
				code=${?} 
				break ;;
			("..") args+=("..") 
				break ;;
			("${ENHANCD_ARG_SINGLE_DOT}") args+=("$(__enhancd::sources::current_dirs | __enhancd::filter::interactive)") 
				code=${?} 
				break ;;
			(".") args+=(".") 
				break ;;
			("${ENHANCD_ARG_HOME}") args+=("$(__enhancd::sources::home | __enhancd::filter::interactive)") 
				code=${?} 
				break ;;
			(--) opts+=("${1}") 
				shift
				args+=("$(__enhancd::sources::history "${1}" | __enhancd::filter::interactive)") 
				code=${?} 
				break ;;
			(-* | --*) if __enhancd::helper::is_default_flag "${1}"
				then
					opts+=("${1}") 
				else
					local opt="${1}" 
					local func cond format
					cond="$(__enhancd::ltsv::get "${opt}" "condition")" 
					func="$(__enhancd::ltsv::get "${opt}" "func")" 
					format="$(__enhancd::ltsv::get "${opt}" "format")" 
					if ! __enhancd::command::run "${cond}" &> /dev/null
					then
						echo "${opt}: does not meet '${cond}'" >&2
						return 1
					fi
					if [[ -z ${func} ]]
					then
						echo "${opt}: 'func' label is required" >&2
						return 1
					fi
					if [[ -n ${format} ]] && [[ ${format//\%/} == "${format}" ]]
					then
						echo "${opt}: 'format' label needs to include '%' (selected line)" >&2
						return 1
					fi
					local selected
					if [[ -z ${format} ]]
					then
						selected="$(__enhancd::command::run "${func}" | __enhancd::filter::interactive)" 
						code=${?} 
					else
						selected="$(__enhancd::command::run "${func}" | __enhancd::filter::interactive | xargs -I% echo $(eval printf "%s" "${format}"))" 
						code=${?} 
					fi
					args+=("${selected}") 
					break
				fi ;;
			(*) args+=("$(__enhancd::sources::history "${1}" | __enhancd::filter::interactive)") 
				code=${?}  ;;
		esac
		shift
	done
	case ${#args[@]} in
		(0) args+=("$(__enhancd::sources::home | __enhancd::filter::interactive)") 
			code=${?}  ;;
	esac
	case "${code}" in
		(0) __enhancd::cd::builtin "${opts[@]}" "${args[@]}"
			return ${?} ;;
		(*) return 1 ;;
	esac
}
__enhancd::cd::after () {
	local list
	list="$(__enhancd::history::update)" 
	if [[ -n ${list} ]]
	then
		echo "${list}" >| "${ENHANCD_DIR}/enhancd.log"
	fi
	if [[ -n ${ENHANCD_HOOK_AFTER_CD} ]]
	then
		eval "${ENHANCD_HOOK_AFTER_CD}"
	fi
}
__enhancd::cd::before () {
	:
}
__enhancd::cd::builtin () {
	local -i code=0 
	__enhancd::cd::before
	builtin cd "${@}"
	code=${?} 
	__enhancd::cd::after
	return ${code}
}
__enhancd::cd::ready () {
	__enhancd::helper::parse_filter_string "${ENHANCD_FILTER}" &> /dev/null && [[ -s ${ENHANCD_DIR}/enhancd.log ]]
	return ${?}
}
__enhancd::command::awk () {
	if type gawk &> /dev/null
	then
		gawk ${1:+"${@}"}
	else
		command awk ${1:+"${@}"}
	fi
}
__enhancd::command::grep () {
	{
		if [[ -n ${1} ]] && [[ -f ${1} ]]
		then
			command cat "${1}"
			shift
		else
			command cat <&0
		fi
	} | command grep "${@}" 2> /dev/null
}
__enhancd::command::run () {
	local cond="${1}" 
	${SHELL:-bash} -c "${cond}"
	return ${?}
}
__enhancd::command::which () {
	if [[ -z ${1} ]]
	then
		return 1
	fi
	type "${1}" &> /dev/null
}
__enhancd::filepath::abs () {
	local cwd dir
	cwd="${PWD%/*}" 
	dir="${1}" 
	if [[ -p /dev/stdin ]]
	then
		dir="$(command cat <&0)" 
	fi
	if [[ -z ${dir} ]]
	then
		return 1
	fi
	__enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/to_abspath.awk" -v cwd="${cwd}" -v dir="${dir}"
}
__enhancd::filepath::current_dir () {
	echo "${PWD:-$(command pwd)}"
}
__enhancd::filepath::get_dirs_in_cwd () {
	if type fd &> /dev/null
	then
		command fd --type d --hidden -E .git
		return ${?}
	fi
	LC_ALL=C command find . ! -name . \( -name '.*' -prune -o -type d -print \) | cut -c3-
}
__enhancd::filepath::get_parent_dirs () {
	__enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/step_by_step.awk" -v dir="${1:-$PWD}"
}
__enhancd::filepath::split () {
	__enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/split.awk" -v arg="${1:-$PWD}"
}
__enhancd::filepath::walk () {
	local -a dirs
	IFS=$'\n' dirs=("${PWD}" $(__enhancd::filepath::get_parent_dirs "${1:-${PWD}}")) 
	for dir in "${dirs[@]}"
	do
		command find "${dir}" -maxdepth 1 -type d -name '\.*' -prune -o -type d -print
	done
}
__enhancd::filter::exclude () {
	__enhancd::command::grep -v -x -F "${1}" || true
}
__enhancd::filter::exists () {
	local line
	while read line
	do
		if [[ -d ${line} ]]
		then
			echo "${line}"
		fi
	done
}
__enhancd::filter::fuzzy () {
	if [[ -z ${1} ]]
	then
		cat <&0
	else
		__enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/fuzzy.awk" -v search_string="${1}"
	fi
}
__enhancd::filter::interactive () {
	local stdin="${1}" 
	if [[ -z ${stdin} ]] || [[ -p /dev/stdin ]]
	then
		stdin="$(command cat <&0)" 
	fi
	if [[ -z ${stdin} ]]
	then
		echo "no entry" >&2
		return 1
	fi
	local filter
	filter="$(__enhancd::helper::parse_filter_string "${ENHANCD_FILTER}")" 
	if ${ENHANCD_USE_ABBREV}
	then
		filter="__enhancd::filter::replace ${HOME} \~ | ${filter} | __enhancd::filter::replace \~ ${HOME}" 
	fi
	local -i count
	count="$(echo "${stdin}" | __enhancd::command::grep -c "")" 
	case "${count}" in
		(1) if [[ -n ${stdin} ]]
			then
				echo "${stdin}"
			else
				return 1
			fi ;;
		(*) local selected
			selected="$(echo "${stdin}" | eval "${filter}")" 
			if [[ -z ${selected} ]]
			then
				return 0
			fi
			echo "${selected}" ;;
	esac
}
__enhancd::filter::limit () {
	command head -n "${1:-10}"
}
__enhancd::filter::replace () {
	local old new
	old="${1:?too few argument}" 
	new="${2:-""}" 
	__enhancd::command::awk -v old="${old}" -v new="${new}" 'sub(old, new, $0) {print $0}'
}
__enhancd::filter::reverse () {
	{
		if [[ -n ${1} ]] && [[ -f ${1} ]]
		then
			command cat "${1}"
		else
			command cat <&0
		fi
	} | __enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/reverse.awk" 2> /dev/null
}
__enhancd::filter::unique () {
	{
		if [[ -n ${1} ]] && [[ -f ${1} ]]
		then
			command cat "${1}"
		else
			command cat <&0
		fi
	} | __enhancd::command::awk '!a[$0]++' 2> /dev/null
}
__enhancd::helper::is_default_flag () {
	local opt="${1}" 
	case ${SHELL} in
		(*bash) case "${opt}" in
				("-P" | "-L" | "-e" | "-@") return 0 ;;
			esac ;;
		(*zsh) case "${opt}" in
				("-q" | "-s" | "-L" | "-P") return 0 ;;
			esac ;;
	esac
	return 1
}
__enhancd::helper::parse_filter_string () {
	local item str
	if [[ -z ${1} ]]
	then
		return 1
	fi
	str="${1}:" 
	while [[ -n ${str} ]]
	do
		item=${str%%:*} 
		str=${str#*:} 
		if __enhancd::command::which "${item%% *}"
		then
			echo "${item}"
			return 0
		else
			continue
		fi
	done
	return 1
}
__enhancd::history::exists () {
	local dir="${1}" 
	if [[ -z ${dir} ]]
	then
		return 1
	fi
	__enhancd::history::open | __enhancd::command::grep "${dir}" &> /dev/null
}
__enhancd::history::list () {
	__enhancd::history::open | __enhancd::filter::reverse | __enhancd::filter::unique | __enhancd::filter::exists | __enhancd::filter::fuzzy "${@}" | __enhancd::filter::exclude "${PWD}"
}
__enhancd::history::open () {
	if [[ -f ${ENHANCD_DIR}/enhancd.log ]]
	then
		command cat "${ENHANCD_DIR}/enhancd.log"
		return ${?}
	fi
	return 1
}
__enhancd::history::update () {
	{
		__enhancd::history::exists "${PWD}" || __enhancd::filepath::walk
		__enhancd::history::open
		echo "${HOME}"
	} | __enhancd::filter::reverse | __enhancd::filter::unique | __enhancd::filter::reverse
	__enhancd::filepath::current_dir
}
__enhancd::ltsv::get () {
	local opt="${1:?value of key short or long required}" key="${2}" 
	__enhancd::ltsv::open | __enhancd::command::grep -v -E '^(//|#)' | __enhancd::ltsv::parse -v opt="${opt}" -v key="${key}" -q 'ltsv("short") == opt || ltsv("long") == opt { if (key=="") { print $0 } else { print ltsv(key) } }'
}
__enhancd::ltsv::open () {
	command cat "${ENHANCD_ROOT}/config.ltsv" 2> /dev/null
	command cat "${ENHANCD_DIR}/config.ltsv" 2> /dev/null
	command cat "${HOME}/.config/enhancd/config.ltsv" 2> /dev/null
}
__enhancd::ltsv::parse () {
	local -a args
	local query
	while (( ${#} > 0 ))
	do
		case "${1}" in
			(-q) query="${2}" 
				shift ;;
			(-v) args+=("-v" "${2}") 
				shift ;;
			(-f) args+=("-f" "${ENHANCD_ROOT}/functions/enhancd/lib/ltsv.awk") 
				args+=("-f" "${2}") 
				query="" 
				shift ;;
		esac
		shift
	done
	local default_query='{print $0}' 
	local ltsv_script="$(command cat "${ENHANCD_ROOT}/functions/enhancd/lib/ltsv.awk")" 
	local awk_scripts="${ltsv_script} ${query:-${default_query}}" 
	__enhancd::command::awk ${args[@]} "${awk_scripts}"
}
__enhancd::sources::current_dirs () {
	if ! ${ENHANCD_ENABLE_SINGLE_DOT}
	then
		echo "."
		return 0
	fi
	__enhancd::filepath::get_dirs_in_cwd
}
__enhancd::sources::history () {
	local dir="${1}" 
	if [[ -d ${dir} ]]
	then
		echo "${dir}"
		return 0
	fi
	if [[ -n $CDPATH ]]
	then
		__enhancd::command::awk -f "${ENHANCD_ROOT}/functions/enhancd/lib/cdpath.awk" -v cdpath="${CDPATH}" -v dir="${dir}" && return 0
	fi
	__enhancd::history::list "${dir}"
}
__enhancd::sources::home () {
	if ! ${ENHANCD_ENABLE_HOME}
	then
		echo "${HOME}"
		return 0
	fi
	{
		echo "${HOME}"
		__enhancd::history::list
	} | __enhancd::filter::unique
}
__enhancd::sources::mru () {
	if ! ${ENHANCD_ENABLE_HYPHEN}
	then
		echo "${OLDPWD}"
		return 0
	fi
	__enhancd::history::list "${1}" | __enhancd::filter::exclude "${HOME}" | __enhancd::filter::limit "${ENHANCD_HYPHEN_NUM}"
}
__enhancd::sources::parent_dirs () {
	if ! ${ENHANCD_ENABLE_DOUBLE_DOT}
	then
		echo ".."
		return 0
	fi
	__enhancd::filepath::get_parent_dirs "${PWD}"
}
__gh_debug () {
	local file="$BASH_COMP_DEBUG_FILE" 
	if [[ -n ${file} ]]
	then
		echo "$*" >> "${file}"
	fi
}
__git_prompt_git () {
	GIT_OPTIONAL_LOCKS=0 command git "$@"
}
__starship_get_time () {
	(( STARSHIP_CAPTURED_TIME = int(rint(EPOCHREALTIME * 1000)) ))
}
__sudo-replace-buffer () {
	local old=$1 new=$2 space=${2:+ } 
	if [[ $CURSOR -le ${#old} ]]
	then
		BUFFER="${new}${space}${BUFFER#$old }" 
		CURSOR=${#new} 
	else
		LBUFFER="${new}${space}${LBUFFER#$old }" 
	fi
}
__zoxide_cd () {
	\builtin cd -- "$@"
}
__zoxide_doctor () {
	[[ ${_ZO_DOCTOR:-1} -ne 0 ]] || return 0
	[[ ${chpwd_functions[(Ie)__zoxide_hook]:-} -eq 0 ]] || return 0
	_ZO_DOCTOR=0 
	\builtin printf '%s\n' 'zoxide: detected a possible configuration issue.' 'Please ensure that zoxide is initialized right at the end of your shell configuration file (usually ~/.zshrc).' '' 'If the issue persists, consider filing an issue at:' 'https://github.com/ajeetdsouza/zoxide/issues' '' 'Disable this message by setting _ZO_DOCTOR=0.' '' >&2
}
__zoxide_hook () {
	\command zoxide add -- "$(__zoxide_pwd)"
}
__zoxide_pwd () {
	\builtin pwd -L
}
__zoxide_z () {
	__zoxide_doctor
	if [[ "$#" -eq 0 ]]
	then
		__zoxide_cd ~
	elif [[ "$#" -eq 1 ]] && {
			[[ -d "$1" ]] || [[ "$1" = '-' ]] || [[ "$1" =~ ^[-+][0-9]+$ ]]
		}
	then
		__zoxide_cd "$1"
	elif [[ "$#" -eq 2 ]] && [[ "$1" = "--" ]]
	then
		__zoxide_cd "$2"
	else
		\builtin local result
		result="$(\command zoxide query --exclude "$(__zoxide_pwd)" -- "$@")"  && __zoxide_cd "${result}"
	fi
}
__zoxide_zi () {
	__zoxide_doctor
	\builtin local result
	result="$(\command zoxide query --interactive -- "$@")"  && __zoxide_cd "${result}"
}
