_check_aliases () {
	local typed="$1" 
	local expanded="${2:-$1}" 
	local found_aliases
	found_aliases=() 
	local best_match="" 
	local best_match_value="" 
	local key
	local value
	if [[ "$typed" = "sudo "* ]]
	then
		return
	fi
	for key in "${(@k)aliases}"
	do
		value="${aliases[$key]}" 
		if [[ ${YSU_IGNORED_ALIASES[(r)$key]} == "$key" ]]
		then
			continue
		fi
		if [[ "$expanded" = "$value" || "$expanded" = "$value "* ]]
		then
			if [[ "${#value}" -gt "${#key}" ]]
			then
				found_aliases+="$key" 
				if [[ "${#value}" -gt "${#best_match_value}" ]]
				then
					best_match="$key" 
					best_match_value="$value" 
				elif [[ "${#value}" -eq "${#best_match}" && ${#key} -lt "${#best_match}" ]]
				then
					best_match="$key" 
					best_match_value="$value" 
				fi
			fi
		fi
	done
	if [[ "$YSU_MODE" = "ALL" ]]
	then
		for key in ${(@ok)found_aliases}
		do
			value="${aliases[$key]}" 
			if [[ "$typed" = "$key" || "$typed" = "$key "* ]] || _typed_resolves_to_alias "$typed" "$key"
			then
				continue
			fi
			ysu_message "alias" "$value" "$key"
			_check_ysu_hardcore "$key"
		done
	elif [[ ( -z "$YSU_MODE" || "$YSU_MODE" = "BESTMATCH" ) && -n "$best_match" ]]
	then
		value="${aliases[$best_match]}" 
		if [[ "$typed" = "$best_match" || "$typed" = "$best_match "* ]] || _typed_resolves_to_alias "$typed" "$best_match"
		then
			return
		fi
		ysu_message "alias" "$value" "$best_match"
		_check_ysu_hardcore "$best_match"
	fi
}
_check_git_aliases () {
	local typed="$1" 
	local expanded="$2" 
	if [[ "$typed" = "sudo "* ]]
	then
		return
	fi
	if [[ "$typed" = "git "* ]]
	then
		local found=false 
		git config --get-regexp "^alias\..+$" | sort | while read key value
		do
			key="${key#alias.}" 
			if [[ -z "$value" ]]
			then
				value="${key#* }" 
				key="${key%% *}" 
			fi
			if [[ "$expanded" = "git $value" || "$expanded" = "git $value "* ]]
			then
				ysu_message "git alias" "$value" "git $key"
				found=true 
			fi
		done
		if $found
		then
			_check_ysu_hardcore
		fi
	fi
}
_check_global_aliases () {
	local typed="$1" 
	local expanded="$2" 
	local found=false 
	local tokens
	local key
	local value
	local entry
	if [[ "$typed" = "sudo "* ]]
	then
		return
	fi
	alias -g | sort | while IFS="=" read -r key value
	do
		key="${key## }" 
		key="${key%% }" 
		value="${(Q)value}" 
		if [[ ${YSU_IGNORED_GLOBAL_ALIASES[(r)$key]} == "$key" ]]
		then
			continue
		fi
		if [[ "$typed" = *" $value "* || "$typed" = *" $value" || "$typed" = "$value "* || "$typed" = "$value" ]]
		then
			ysu_message "global alias" "$value" "$key"
			found=true 
		fi
	done
	if $found
	then
		_check_ysu_hardcore
	fi
}
_check_ysu_hardcore () {
	local alias_name="$1" 
	local hardcore_lookup="${YSU_HARDCORE_ALIASES[(r)$alias_name]}" 
	if (( ${+YSU_HARDCORE} )) || [[ -n "$hardcore_lookup" && "$hardcore_lookup" == "$alias_name" ]]
	then
		_write_ysu_buffer "${BOLD}${RED}You Should Use hardcore mode enabled. Use your aliases!${NONE}\n"
		kill -s INT $$
	fi
}
_chezmoi () {
	local shellCompDirectiveError=1 
	local shellCompDirectiveNoSpace=2 
	local shellCompDirectiveNoFileComp=4 
	local shellCompDirectiveFilterFileExt=8 
	local shellCompDirectiveFilterDirs=16 
	local shellCompDirectiveKeepOrder=32 
	local lastParam lastChar flagPrefix requestComp out directive comp lastComp noSpace keepOrder
	local -a completions
	__chezmoi_debug "\n========= starting completion logic =========="
	__chezmoi_debug "CURRENT: ${CURRENT}, words[*]: ${words[*]}"
	words=("${=words[1,CURRENT]}") 
	__chezmoi_debug "Truncated words[*]: ${words[*]},"
	lastParam=${words[-1]} 
	lastChar=${lastParam[-1]} 
	__chezmoi_debug "lastParam: ${lastParam}, lastChar: ${lastChar}"
	setopt local_options BASH_REMATCH
	if [[ "${lastParam}" =~ '-.*=' ]]
	then
		flagPrefix="-P ${BASH_REMATCH}" 
	fi
	requestComp="${words[1]} __complete ${words[2,-1]}" 
	if [ "${lastChar}" = "" ]
	then
		__chezmoi_debug "Adding extra empty parameter"
		requestComp="${requestComp} \"\"" 
	fi
	__chezmoi_debug "About to call: eval ${requestComp}"
	out=$(eval ${requestComp} 2>/dev/null) 
	__chezmoi_debug "completion output: ${out}"
	local lastLine
	while IFS='\n' read -r line
	do
		lastLine=${line} 
	done < <(printf "%s\n" "${out[@]}")
	__chezmoi_debug "last line: ${lastLine}"
	if [ "${lastLine[1]}" = : ]
	then
		directive=${lastLine[2,-1]} 
		local suffix
		(( suffix=${#lastLine}+2))
		out=${out[1,-$suffix]} 
	else
		__chezmoi_debug "No directive found.  Setting do default"
		directive=0 
	fi
	__chezmoi_debug "directive: ${directive}"
	__chezmoi_debug "completions: ${out}"
	__chezmoi_debug "flagPrefix: ${flagPrefix}"
	if [ $((directive & shellCompDirectiveError)) -ne 0 ]
	then
		__chezmoi_debug "Completion received error. Ignoring completions."
		return
	fi
	local activeHelpMarker="_activeHelp_ " 
	local endIndex=${#activeHelpMarker} 
	local startIndex=$((${#activeHelpMarker}+1)) 
	local hasActiveHelp=0 
	while IFS='\n' read -r comp
	do
		if [ "${comp[1,$endIndex]}" = "$activeHelpMarker" ]
		then
			__chezmoi_debug "ActiveHelp found: $comp"
			comp="${comp[$startIndex,-1]}" 
			if [ -n "$comp" ]
			then
				compadd -x "${comp}"
				__chezmoi_debug "ActiveHelp will need delimiter"
				hasActiveHelp=1 
			fi
			continue
		fi
		if [ -n "$comp" ]
		then
			comp=${comp//:/\\:} 
			local tab="$(printf '\t')" 
			comp=${comp//$tab/:} 
			__chezmoi_debug "Adding completion: ${comp}"
			completions+=${comp} 
			lastComp=$comp 
		fi
	done < <(printf "%s\n" "${out[@]}")
	if [ $hasActiveHelp -eq 1 ]
	then
		if [ ${#completions} -ne 0 ] || [ $((directive & shellCompDirectiveNoFileComp)) -eq 0 ]
		then
			__chezmoi_debug "Adding activeHelp delimiter"
			compadd -x "--"
			hasActiveHelp=0 
		fi
	fi
	if [ $((directive & shellCompDirectiveNoSpace)) -ne 0 ]
	then
		__chezmoi_debug "Activating nospace."
		noSpace="-S ''" 
	fi
	if [ $((directive & shellCompDirectiveKeepOrder)) -ne 0 ]
	then
		__chezmoi_debug "Activating keep order."
		keepOrder="-V" 
	fi
	if [ $((directive & shellCompDirectiveFilterFileExt)) -ne 0 ]
	then
		local filteringCmd
		filteringCmd='_files' 
		for filter in ${completions[@]}
		do
			if [ ${filter[1]} != '*' ]
			then
				filter="\*.$filter" 
			fi
			filteringCmd+=" -g $filter" 
		done
		filteringCmd+=" ${flagPrefix}" 
		__chezmoi_debug "File filtering command: $filteringCmd"
		_arguments '*:filename:'"$filteringCmd"
	elif [ $((directive & shellCompDirectiveFilterDirs)) -ne 0 ]
	then
		local subdir
		subdir="${completions[1]}" 
		if [ -n "$subdir" ]
		then
			__chezmoi_debug "Listing directories in $subdir"
			pushd "${subdir}" > /dev/null 2>&1
		else
			__chezmoi_debug "Listing directories in ."
		fi
		local result
		_arguments '*:dirname:_files -/'" ${flagPrefix}"
		result=$? 
		if [ -n "$subdir" ]
		then
			popd > /dev/null 2>&1
		fi
		return $result
	else
		__chezmoi_debug "Calling _describe"
		if eval _describe $keepOrder "completions" completions $flagPrefix $noSpace
		then
			__chezmoi_debug "_describe found some completions"
			return 0
		else
			__chezmoi_debug "_describe did not find completions."
			__chezmoi_debug "Checking if we should do file completion."
			if [ $((directive & shellCompDirectiveNoFileComp)) -ne 0 ]
			then
				__chezmoi_debug "deactivating file completion"
				return 1
			else
				__chezmoi_debug "Activating file completion"
				_arguments '*:filename:_files'" ${flagPrefix}"
			fi
		fi
	fi
}
_chezmoi_completion_defer () {
	if command -v chezmoi &> /dev/null
	then
		_chezmoi_cache="$HOME/.cache/zsh/chezmoi_completion.zsh" 
		if [[ ! -f "$_chezmoi_cache" ]] || [[ $(command -v chezmoi) -nt "$_chezmoi_cache" ]]
		then
			mkdir -p "$HOME/.cache/zsh"
			chezmoi completion zsh > "$_chezmoi_cache" 2> /dev/null
		fi
		[[ -f "$_chezmoi_cache" ]] && source "$_chezmoi_cache"
	fi
}
