_mise () {
	typeset -A opt_args
	local curcontext="$curcontext" cache_policy 
	if ! type -p usage &> /dev/null
	then
		echo >&2
		echo "Error: usage CLI not found. This is required for completions to work in mise." >&2
		echo "See https://usage.jdx.dev for more information." >&2
		return 1
	fi
	local spec_file="${TMPDIR:-/tmp}/usage__usage_spec_mise_2026_4_6.spec" 
	if [[ ! -f "$spec_file" ]]
	then
		mise usage >| "$spec_file"
	fi
	local -a completions=() 
	while IFS= read -r line
	do
		completions+=("$line") 
	done < <(command usage complete-word --shell zsh -f "$spec_file" -- "${words[@]}")
	_describe 'completions' completions -S ''
	return 0
}
_mise_completion_defer () {
	if command -v mise &> /dev/null
	then
		_mise_cache="$HOME/.cache/zsh/mise_completion.zsh" 
		if [[ ! -f "$_mise_cache" ]] || [[ $(command -v mise) -nt "$_mise_cache" ]]
		then
			mkdir -p "$HOME/.cache/zsh"
			mise completion zsh > "$_mise_cache" 2> /dev/null
		fi
		[[ -f "$_mise_cache" ]] && source "$_mise_cache"
	fi
}
_mise_hook () {
	eval "$(/nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise hook-env -s zsh)"
