_mise_hook_chpwd () {
	export __MISE_ZSH_CHPWD_RAN=1 
	eval "$(/nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise hook-env -s zsh --reason chpwd)"
