_mise_hook_precmd () {
	if [[ "${__MISE_ZSH_CHPWD_RAN:-0}" == "1" ]]
	then
		export __MISE_ZSH_CHPWD_RAN=0 
		return
	fi
	eval "$(/nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise hook-env -s zsh --reason precmd)"
}
_mise_preexec_once () {
	if (( $+functions[_mise_hook] ))
	then
		_mise_hook
	fi
	preexec_functions=(${preexec_functions:#_mise_preexec_once}) 
	unset -f _mise_preexec_once
