	then
		_arguments_options=(-s -S -C) 
	else
		_arguments_options=(-s -C) 
	fi
	local context curcontext="$curcontext" state line 
	_arguments "${_arguments_options[@]}" : '-W+[Watch mode with custom interval]:second:_default' '--watch-interval=[Watch mode with custom interval]:second:_default' '*-i+[Insert column to slot]:kind:_default' '*--insert=[Insert column to slot]:kind:_default' '--only=[Specified column only]:kind:_default' '(--sortd -t --tree)--sorta=[Sort column by ascending]:kind:_default' '(--sorta -t --tree)--sortd=[Sort column by descending]:kind:_default' '-c+[Color mode]:COLOR:(auto always disable)' '--color=[Color mode]:COLOR:(auto always disable)' '--theme=[Theme mode]:THEME:(auto dark light)' '-p+[Pager mode]:PAGER:(auto always disable)' '--pager=[Pager mode]:PAGER:(auto always disable)' '--interval=[Interval to calculate throughput]:millisec:_default' '--use-config=[Use built-in configuration]:name:(default large)' '--load-config=[Load configuration from file]:path:_files' '--gen-completion=[Generate shell completion file]:shell:(bash elvish fish powershell zsh)' '--gen-completion-out=[Generate shell completion file and write to stdout]:shell:(bash elvish fish powershell zsh)' '--procfs=[Path to procfs]:PROCFS:_files' '(-o --or -d --nand -r --nor)-a[AND  logic for multi-keyword]' '(-o --or -d --nand -r --nor)--and[AND  logic for multi-keyword]' '(-a --and -d --nand -r --nor)-o[OR   logic for multi-keyword]' '(-a --and -d --nand -r --nor)--or[OR   logic for multi-keyword]' '(-a --and -o --or -r --nor)-d[NAND logic for multi-keyword]' '(-a --and -o --or -r --nor)--nand[NAND logic for multi-keyword]' '(-a --and -o --or -d --nand)-r[NOR  logic for multi-keyword]' '(-a --and -o --or -d --nand)--nor[NOR  logic for multi-keyword]' '-l[Show list of kind]' '--list[Show list of kind]' '--thread[Show thread]' '-t[Tree view]' '--tree[Tree view]' '-w[Watch mode with default interval (1s)]' '--watch[Watch mode with default interval (1s)]' '--json[JSON output]' '--gen-config[Generate configuration sample file]' '--no-header[Suppress header]' '--debug[Show debug message]' '-h[Print help (see more with '\''--help'\'')]' '--help[Print help (see more with '\''--help'\'')]' '-V[Print version]' '--version[Print version]' '*::KEYWORD -- Keywords for search:_default' && ret=0 
}
