_starship () {
	typeset -A opt_args
	typeset -a _arguments_options
	local ret=1 
	if is-at-least 5.2
	then
		_arguments_options=(-s -S -C) 
	else
		_arguments_options=(-s -C) 
	fi
	local context curcontext="$curcontext" state line 
	_arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' '-V[Print version]' '--version[Print version]' ":: :_starship_commands" "*::: :->starship" && ret=0 
	case $state in
		(starship) words=($line[1] "${words[@]}") 
			(( CURRENT += 1 ))
			curcontext="${curcontext%:*:*}:starship-command-$line[1]:" 
			case $line[1] in
				(bug-report) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(completions) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' ':shell:(bash elvish fish nushell powershell zsh)' && ret=0  ;;
				(config) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' '::name -- Configuration key to edit:_default' '::value -- Value to place into that key:_default' && ret=0  ;;
				(explain) _arguments "${_arguments_options[@]}" : '-s+[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '--status=[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '*--pipestatus=[Bash, Fish and Zsh support returning codes for each process in a pipeline]:PIPESTATUS:_default' '-w+[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '--terminal-width=[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '-p+[The path that the prompt should render for]:PATH:_files' '--path=[The path that the prompt should render for]:PATH:_files' '-P+[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '--logical-path=[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '-d+[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '--cmd-duration=[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '-k+[The keymap of fish/zsh/cmd]:KEYMAP:_default' '--keymap=[The keymap of fish/zsh/cmd]:KEYMAP:_default' '-j+[The number of currently running jobs]:JOBS:_default' '--jobs=[The number of currently running jobs]:JOBS:_default' '--shlvl=[The current value of SHLVL, for shells that mis-handle it in \$()]:SHLVL:_default' '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(init) _arguments "${_arguments_options[@]}" : '--print-full-init[]' '-h[Print help]' '--help[Print help]' ':shell:_default' && ret=0  ;;
				(module) _arguments "${_arguments_options[@]}" : '-s+[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '--status=[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '*--pipestatus=[Bash, Fish and Zsh support returning codes for each process in a pipeline]:PIPESTATUS:_default' '-w+[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '--terminal-width=[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '-p+[The path that the prompt should render for]:PATH:_files' '--path=[The path that the prompt should render for]:PATH:_files' '-P+[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '--logical-path=[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '-d+[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '--cmd-duration=[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '-k+[The keymap of fish/zsh/cmd]:KEYMAP:_default' '--keymap=[The keymap of fish/zsh/cmd]:KEYMAP:_default' '-j+[The number of currently running jobs]:JOBS:_default' '--jobs=[The number of currently running jobs]:JOBS:_default' '--shlvl=[The current value of SHLVL, for shells that mis-handle it in \$()]:SHLVL:_default' '-l[List out all supported modules]' '--list[List out all supported modules]' '-h[Print help]' '--help[Print help]' '::name -- The name of the module to be printed:_default' && ret=0  ;;
				(preset) _arguments "${_arguments_options[@]}" : '(-l --list)-o+[Output the preset to a file instead of stdout]:OUTPUT:_files' '(-l --list)--output=[Output the preset to a file instead of stdout]:OUTPUT:_files' '-l[List out all preset names]' '--list[List out all preset names]' '-h[Print help]' '--help[Print help]' '::name -- The name of preset to be printed:(bracketed-segments catppuccin-powerline gruvbox-rainbow jetpack nerd-font-symbols no-empty-icons no-nerd-font no-runtime-versions pastel-powerline plain-text-symbols pure-preset tokyo-night)' && ret=0  ;;
				(print-config) _arguments "${_arguments_options[@]}" : '-d[Print the default instead of the computed config]' '--default[Print the default instead of the computed config]' '-h[Print help]' '--help[Print help]' '*::name -- Configuration keys to print:_default' && ret=0  ;;
				(prompt) _arguments "${_arguments_options[@]}" : '(--right)--profile=[Print the prompt with the specified profile name (instead of the standard left prompt)]:PROFILE:_default' '-s+[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '--status=[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '*--pipestatus=[Bash, Fish and Zsh support returning codes for each process in a pipeline]:PIPESTATUS:_default' '-w+[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '--terminal-width=[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '-p+[The path that the prompt should render for]:PATH:_files' '--path=[The path that the prompt should render for]:PATH:_files' '-P+[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '--logical-path=[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '-d+[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '--cmd-duration=[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '-k+[The keymap of fish/zsh/cmd]:KEYMAP:_default' '--keymap=[The keymap of fish/zsh/cmd]:KEYMAP:_default' '-j+[The number of currently running jobs]:JOBS:_default' '--jobs=[The number of currently running jobs]:JOBS:_default' '--shlvl=[The current value of SHLVL, for shells that mis-handle it in \$()]:SHLVL:_default' '--right[Print the right prompt (instead of the standard left prompt)]' '(--right --profile)--continuation[Print the continuation prompt (instead of the standard left prompt)]' '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(session) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(time) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(timings) _arguments "${_arguments_options[@]}" : '-s+[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '--status=[The status code of the previously run command as an unsigned or signed 32bit integer]:STATUS_CODE:_default' '*--pipestatus=[Bash, Fish and Zsh support returning codes for each process in a pipeline]:PIPESTATUS:_default' '-w+[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '--terminal-width=[The width of the current interactive terminal]:TERMINAL_WIDTH:_default' '-p+[The path that the prompt should render for]:PATH:_files' '--path=[The path that the prompt should render for]:PATH:_files' '-P+[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '--logical-path=[The logical path that the prompt should render for. This path should be a virtual/logical representation of the PATH argument]:LOGICAL_PATH:_files' '-d+[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '--cmd-duration=[The execution duration of the last command, in milliseconds]:CMD_DURATION:_default' '-k+[The keymap of fish/zsh/cmd]:KEYMAP:_default' '--keymap=[The keymap of fish/zsh/cmd]:KEYMAP:_default' '-j+[The number of currently running jobs]:JOBS:_default' '--jobs=[The number of currently running jobs]:JOBS:_default' '--shlvl=[The current value of SHLVL, for shells that mis-handle it in \$()]:SHLVL:_default' '-h[Print help]' '--help[Print help]' && ret=0  ;;
				(toggle) _arguments "${_arguments_options[@]}" : '-h[Print help]' '--help[Print help]' ':name -- The name of the module to be toggled:_default' '::value -- The key of the config to be toggled:_default' && ret=0  ;;
				(help) _arguments "${_arguments_options[@]}" : ":: :_starship__help_commands" "*::: :->help" && ret=0 
					case $state in
						(help) words=($line[1] "${words[@]}") 
							(( CURRENT += 1 ))
							curcontext="${curcontext%:*:*}:starship-help-command-$line[1]:" 
							case $line[1] in
								(bug-report) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(completions) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(config) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(explain) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(init) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(module) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(preset) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(print-config) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(prompt) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(session) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(time) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(timings) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(toggle) _arguments "${_arguments_options[@]}" : && ret=0  ;;
								(help) _arguments "${_arguments_options[@]}" : && ret=0  ;;
							esac ;;
					esac ;;
			esac ;;
	esac
}
