_typed_resolves_to_alias () {
	local typed_cmd="${1%% *}" 
	local target_alias="$2" 
	local check_value="${aliases[$typed_cmd]}" 
	local check_cmd
	local -A visited_aliases
	visited_aliases[$typed_cmd]=1 
	while [[ -n "$check_value" ]]
	do
		if [[ "$check_value" = "$target_alias" || "$check_value" = "$target_alias "* ]]
		then
			return 0
		fi
		check_cmd="${check_value%% *}" 
		if [[ -n "${visited_aliases[$check_cmd]}" ]]
		then
			break
		fi
		visited_aliases[$check_cmd]=1 
		check_value="${aliases[$check_cmd]}" 
	done
	return 1
}
