_usage_mise_cache_policy () {
	if [[ -z "${lifetime}" ]]
	then
		lifetime=$((60*60*4)) 
	fi
	local -a oldp
	oldp=("$1"(Nms+${lifetime})) 
	(( $#oldp ))
}
