_write_ysu_buffer () {
	_YSU_BUFFER+="$@" 
	local position="${YSU_MESSAGE_POSITION:-before}" 
	if [[ "$position" = "before" ]]
	then
		_flush_ysu_buffer
	elif [[ "$position" != "after" ]]
	then
		(
			printf "${RED}${BOLD}Unknown value for YSU_MESSAGE_POSITION '$position'. " >&2
		)
		(
			printf "Expected value 'before' or 'after'${NONE}\n" >&2
		)
		_flush_ysu_buffer
	fi
}
