check_alias_usage () {
	local limit="${1:-${HISTSIZE:-9000000000000000}}" 
	local key
	declare -A usage
	for key in "${(@k)aliases}"
	do
		usage[$key]=0 
	done
	local -a histfile_lines
	histfile_lines=("${(@f)$(<$HISTFILE)}") 
	histfile_lines=("${histfile_lines[@]#*;}") 
	local current=0 
	local total=${#histfile_lines} 
	if [[ $total -gt $limit ]]
	then
		total=$limit 
	fi
	local entry
	for line in ${histfile_lines[@]}
	do
		for entry in ${(@s/|/)line}
		do
			entry=${entry##*[[:space:]]} 
			local word=${entry[(w)1]} 
			if [[ -n ${usage[$word]} ]]
			then
				(( usage[$word]++ ))
			fi
		done
		(( current++ ))
		printf "Analysing: [$current/$total]\r"
	done
	printf "\r\033[K"
	for key in ${(k)usage}
	do
		echo "${usage[$key]}: ${(q+)key}=${(q+)aliases[$key]}"
	done | sort -rn -k1
}
