command_not_found_handler () {
	if [[ "$1" != "mise" && "$1" != "mise-"* ]] && /nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise hook-not-found -s zsh -- "$1"
	then
		_mise_hook
		"$@"
	elif [ -n "$(declare -f _command_not_found_handler)" ]
	then
		_command_not_found_handler "$@"
	else
		echo "zsh: command not found: $1" >&2
		return 127
	fi
}
compadd () {
	local -A apre hpre dscrs _oad _mesg
	local -a isfile _opts __ expl
	zparseopts -a _opts P:=apre p:=hpre d:=dscrs X+:=expl O:=_oad A:=_oad D:=_oad f=isfile i: S: s: I: x:=_mesg r: R: W: F: M+: E: q e Q n U C J:=__ V:=__ a=__ l=__ k=__ o::=__ 1=__ 2=__
	_ftb_curcontext=${curcontext#:} 
	if (( $#_oad != 0 || ! IN_FZF_TAB )) || {
			-ftb-zstyle -m disabled-on "any"
		} || {
			-ftb-zstyle -m disabled-on "files" && [[ -n $isfile ]]
		}
	then
		builtin compadd "$@"
		return
	fi
	local -a __hits __dscr
	if (( $#dscrs == 1 ))
	then
		__dscr=("${(@P)${(v)dscrs}}") 
	fi
	builtin compadd -A __hits -D __dscr "$@"
	local ret=$? 
	if (( $#__hits == 0 ))
	then
		if is-at-least 5.9 && (( $#_mesg != 0 ))
		then
			builtin compadd -x $_mesg
		fi
		return $ret
	fi
	expl=$expl[2] 
	[[ -n $expl ]] && _ftb_groups+=$expl 
	local -a _ftb_compcap_keys=(apre hpre PREFIX SUFFIX IPREFIX ISUFFIX) 
	local key expanded __tmp_value=$'<\0>' 
	local PREFIX="$PREFIX" 
	local PREFIX_ORIG="$PREFIX" 
	if [[ $_ftb_curcontext == (*approximate*|*correct*) ]]
	then
		PREFIX=${PREFIX/#\(\#a[0-9]##\)/} 
		PREFIX=${PREFIX/#\~\(\#a[0-9]##\)/~} 
		if [[ $PREFIX_ORIG != $PREFIX ]]
		then
			if [[ ${_opts[(I)-U]} -eq 0 ]]
			then
				_opts+=(-U) 
			fi
		fi
	fi
	for key in $_ftb_compcap_keys
	do
		expanded=${(P)key} 
		if [[ -n $expanded ]]
		then
			__tmp_value+=$'\0'$key$'\0'$expanded 
		fi
	done
	PREFIX="$PREFIX_ORIG" 
	if [[ -n $expl ]]
	then
		__tmp_value+=$'\0group\0'$_ftb_groups[(ie)$expl] 
	fi
	if [[ -n $isfile ]]
	then
		__tmp_value+=$'\0realdir\0'${${(Qe)~${:-$IPREFIX$hpre}}} 
	fi
	_opts+=("${(@kv)apre}" "${(@kv)hpre}" $isfile) 
	__tmp_value+=$'\0args\0'${(pj:\1:)_opts} 
	if (( $+builtins[fzf-tab-compcap-generate] ))
	then
		fzf-tab-compcap-generate __hits __dscr __tmp_value
	else
		local dscr word i
		for i in {1..$#__hits}
		do
			word=$__hits[i] dscr=$__dscr[i] 
			if [[ -n $dscr ]]
			then
				dscr=${dscr//$'\n'} 
			elif [[ -n $word ]]
			then
				dscr=$word 
			fi
			_ftb_compcap+=$dscr$'\2'$__tmp_value$'\0word\0'$word 
		done
	fi
	builtin compadd "$@"
}
