enable-fzf-tab () {
	emulate -L zsh -o extended_glob
	(( ! $+_ftb_orig_widget )) || disable-fzf-tab
	typeset -g _ftb_orig_widget="${${$(builtin bindkey '^I')##* }:-expand-or-complete}" 
	if (( ! $+widgets[.fzf-tab-orig-$_ftb_orig_widget] ))
	then
		local compinit_widgets=(complete-word delete-char-or-list expand-or-complete expand-or-complete-prefix list-choices menu-complete menu-expand-or-complete reverse-menu-complete) 
		if [[ $widgets[$_ftb_orig_widget] == builtin && $compinit_widgets[(Ie)$_ftb_orig_widget] != 0 ]]
		then
			zle -C .fzf-tab-orig-$_ftb_orig_widget .$_ftb_orig_widget _main_complete
		else
			zle -A $_ftb_orig_widget .fzf-tab-orig-$_ftb_orig_widget
		fi
	fi
	zstyle -t ':completion:*' list-grouped false
	typeset -g _ftb_orig_list_grouped=$? 
	zstyle ':completion:*' list-grouped false
	bindkey -M emacs '^I' fzf-tab-complete
	bindkey -M viins '^I' fzf-tab-complete
	bindkey -M emacs '^X.' fzf-tab-debug
	bindkey -M viins '^X.' fzf-tab-debug
	autoload +X -Uz _main_complete _approximate
	functions[compadd]=$functions[-ftb-compadd] 
	functions[_ftb__main_complete]=$functions[_main_complete] 
	_main_complete () {
		-ftb-complete "$@"
	}
	functions[_ftb_approximate_orig]=$functions[_approximate] 
	autoload +X -Uz _approximate
	functions[_ftb_approximate_patched]="${functions[_approximate]//builtin[[:space:]]##compadd/-ftb-compadd}" 
	_approximate () {
		unfunction compadd
		{
			if (( IN_FZF_TAB ))
			then
				_ftb_approximate_patched "$@"
			else
				_ftb_approximate_orig "$@"
			fi
		} always {
			functions[compadd]=$functions[-ftb-compadd] 
		}
	}
}
enable_you_should_use () {
	disable_you_should_use
	add-zsh-hook preexec _check_aliases
	add-zsh-hook preexec _check_global_aliases
	add-zsh-hook preexec _check_git_aliases
	add-zsh-hook precmd _flush_ysu_buffer
}
extract () {
	setopt localoptions noautopushd
	if (( $# == 0 ))
	then
		cat >&2 <<'EOF'
Usage: extract [-option] [file ...]

Options:
    -r, --remove    Remove archive after unpacking.
EOF
	fi
	local remove_archive=1 
	if [[ "$1" == "-r" ]] || [[ "$1" == "--remove" ]]
	then
		remove_archive=0 
		shift
	fi
	local pwd="$PWD" 
	while (( $# > 0 ))
	do
		if [[ ! -f "$1" ]]
		then
			echo "extract: '$1' is not a valid file" >&2
			shift
			continue
		fi
		local success=0 
		local file="$1" full_path="${1:A}" 
		local extract_dir="${1:t:r}" 
		if [[ $extract_dir =~ '\.tar$' ]]
		then
			extract_dir="${extract_dir:r}" 
		fi
		if [[ -e "$extract_dir" ]]
		then
			local rnd="${(L)"${$(( [##36]$RANDOM*$RANDOM ))}":1:5}" 
			extract_dir="${extract_dir}-${rnd}" 
		fi
		command mkdir -p "$extract_dir"
		builtin cd -q "$extract_dir"
		echo "extract: extracting to $extract_dir" >&2
		case "${file:l}" in
			(*.tar.gz|*.tgz) (( $+commands[pigz] )) && {
					tar -I pigz -xvf "$full_path"
				} || tar zxvf "$full_path" ;;
			(*.tar.bz2|*.tbz|*.tbz2) (( $+commands[pbzip2] )) && {
					tar -I pbzip2 -xvf "$full_path"
				} || tar xvjf "$full_path" ;;
			(*.tar.xz|*.txz) (( $+commands[pixz] )) && {
					tar -I pixz -xvf "$full_path"
				} || {
					tar --xz --help &> /dev/null && tar --xz -xvf "$full_path" || xzcat "$full_path" | tar xvf -
				} ;;
			(*.tar.zma|*.tlz) tar --lzma --help &> /dev/null && tar --lzma -xvf "$full_path" || lzcat "$full_path" | tar xvf - ;;
			(*.tar.zst|*.tzst) tar --zstd --help &> /dev/null && tar --zstd -xvf "$full_path" || zstdcat "$full_path" | tar xvf - ;;
			(*.tar) tar xvf "$full_path" ;;
			(*.tar.lz) (( $+commands[lzip] )) && tar xvf "$full_path" ;;
			(*.tar.lz4) lz4 -c -d "$full_path" | tar xvf - ;;
			(*.tar.lrz) (( $+commands[lrzuntar] )) && lrzuntar "$full_path" ;;
			(*.gz) (( $+commands[pigz] )) && pigz -cdk "$full_path" > "${file:t:r}" || gunzip -ck "$full_path" > "${file:t:r}" ;;
			(*.bz2) (( $+commands[pbzip2] )) && pbzip2 -d "$full_path" || bunzip2 "$full_path" ;;
			(*.xz) unxz "$full_path" ;;
			(*.lrz) (( $+commands[lrunzip] )) && lrunzip "$full_path" ;;
			(*.lz4) lz4 -d "$full_path" ;;
			(*.lzma) unlzma "$full_path" ;;
			(*.z) uncompress "$full_path" ;;
			(*.zip|*.war|*.jar|*.ear|*.sublime-package|*.ipa|*.ipsw|*.xpi|*.apk|*.aar|*.whl|*.vsix|*.crx|*.pk3|*.pk4) unzip "$full_path" ;;
			(*.rar) if (( $+commands[unrar] ))
				then
					unrar x -ad "$full_path"
				elif (( $+commands[unar] ))
				then
					unar -o . "$full_path"
				else
					echo "extract: cannot extract RAR files: install unrar or unar" >&2
					success=1 
				fi ;;
			(*.rpm) rpm2cpio "$full_path" | cpio --quiet -id ;;
			(*.7z|*.7z.[0-9]*|*.pk7) 7za x "$full_path" ;;
			(*.deb) command mkdir -p "control" "data"
				ar vx "$full_path" > /dev/null
				builtin cd -q control
				extract ../control.tar.*
				builtin cd -q ../data
				extract ../data.tar.*
				builtin cd -q ..
				command rm *.tar.* debian-binary ;;
			(*.zst) unzstd --stdout "$full_path" > "${file:t:r}" ;;
			(*.cab|*.exe) cabextract "$full_path" ;;
			(*.cpio|*.obscpio) cpio -idmvF "$full_path" ;;
			(*.zpaq) zpaq x "$full_path" ;;
			(*.zlib) zlib-flate -uncompress < "$full_path" > "${file:r}" ;;
			(*) echo "extract: '$file' cannot be extracted" >&2
				success=1  ;;
		esac
		(( success = success > 0 ? success : $? ))
		(( success == 0 && remove_archive == 0 )) && command rm "$full_path"
		shift
		builtin cd -q "$pwd"
		local -a content
		content=("${extract_dir}"/*(DNY2)) 
		if [[ ${#content} -eq 1 && -e "${content[1]}" ]]
		then
			if [[ "${content[1]:t}" == "$extract_dir" ]]
			then
				local tmp_name==(:) 
				tmp_name="${tmp_name:t}" 
				command mv "${content[1]}" "$tmp_name" && command rmdir "$extract_dir" && command mv "$tmp_name" "$extract_dir"
			elif [[ ! -e "${content[1]:t}" ]]
			then
				command mv "${content[1]}" . && command rmdir "$extract_dir"
			fi
		elif [[ ${#content} -eq 0 ]]
		then
			command rmdir "$extract_dir"
		fi
	done
}
