mise () {
	local command
	command="${1:-}" 
	if [ "$#" = 0 ]
	then
		command /nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise
		return
	fi
	shift
	case "$command" in
		(deactivate | shell | sh) if [[ ! " $@ " =~ " --help " ]] && [[ ! " $@ " =~ " -h " ]]
			then
				eval "$(command /nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise "$command" "$@")"
				return $?
			fi ;;
	esac
	command /nix/store/jnq6pyn6dpgdgp5ya1ns67b428iqplpj-mise-2026.4.6/bin/mise "$command" "$@"
}
parse_git_dirty () {
	local STATUS
	local -a FLAGS
	FLAGS=('--porcelain') 
	if [[ "$(__git_prompt_git config --get oh-my-zsh.hide-dirty)" != "1" ]]
	then
		if [[ "${DISABLE_UNTRACKED_FILES_DIRTY:-}" == "true" ]]
		then
			FLAGS+='--untracked-files=no' 
		fi
		case "${GIT_STATUS_IGNORE_SUBMODULES:-}" in
			(git)  ;;
			(*) FLAGS+="--ignore-submodules=${GIT_STATUS_IGNORE_SUBMODULES:-dirty}"  ;;
		esac
		STATUS=$(__git_prompt_git status ${FLAGS} 2> /dev/null | tail -n 1) 
	fi
	if [[ -n $STATUS ]]
	then
		echo "$ZSH_THEME_GIT_PROMPT_DIRTY"
	else
		echo "$ZSH_THEME_GIT_PROMPT_CLEAN"
	fi
}
prompt_nix_shell_precmd () {
	if [[ ( -n ${IN_NIX_SHELL} && ${IN_NIX_SHELL} != "0" ) || ( -n ${IN_NIX_RUN} && ${IN_NIX_RUN} != "0" ) ]]
	then
		if [[ -n ${IN_WHICH_NIX_SHELL} ]]
		then
			NIX_SHELL_NAME=": ${IN_WHICH_NIX_SHELL}" 
		fi
		if [[ -n ${IN_NIX_SHELL} && ${IN_NIX_SHELL} != "0" ]]
		then
			NAME="nix-shell" 
		else
			NAME="nix-run" 
		fi
		NIX_PROMPT="%F{8}[%F{3}${NAME}${NIX_SHELL_NAME}%F{8}]%f" 
		if [[ $PROMPT != *"$NIX_PROMPT"* ]]
		then
			PROMPT="$NIX_PROMPT $PROMPT" 
		fi
	fi
}
